const items = $input.all();
if (items.length === 0) {
  throw new Error("No ready items found");
}
return [items[0]]; // Only return the first row

const videos = items; // items is already an array of video objects

const allReady = videos.every(item => item.json.status === "ready");

return [{
  json: {
    proceed: allReady,
    readyVideos: videos
      .filter(item => item.json.status === "ready")
      .map(item => ({
        id: item.json.id,
        name: item.json.name,
        src_url: item.json.src_url
      })),
    pending: videos
      .filter(item => item.json.status !== "ready")
      .map(item => ({
        id: item.json.id,
        status: item.json.status,
        name: item.json.name
      }))
  }
}];

const videos = items[0].json.readyVideos; // this is the actual array

return videos.map(video => ({
  json: {
    id: video.id,
    name: video.name,
    src_url: video.src_url
  }
}));
